public class BankAccount {
    private String id; private double balance; private boolean closed;
    public BankAccount(String id, double balance) { this.id=id; this.balance=balance; }
    public void deposit(double a) {
        check(!closed, "Account is closed");
        check(a > 0, "Amount must be positive: " + a);
        balance += a;
    }
    public void withdraw(double a) {
        check(!closed, "Account is closed");
        check(a > 0, "Amount must be positive: " + a);
        check(a <= balance, "Insufficient funds: have ₹" + balance + ", need ₹" + a);
        balance -= a;
    }
    public double getBalance() { check(!closed, "Account is closed"); return balance; }
    public void close() { closed = true; }
    public void transfer(BankAccount to, double a) { withdraw(a); to.deposit(a); }
    private void check(boolean cond, String msg) {
        if (!cond) throw new IllegalStateException(msg);
    }
}

