import java.util.*;
import java.util.concurrent.atomic.*;
enum OrderStatus { PENDING, SHIPPED, CANCELLED }
record Order(String id, String product, int qty, double price, OrderStatus status) {
    Order withStatus(OrderStatus s) { return new Order(id, product, qty, price, s); }
}
class OrderService {
    private final Map<String, Order> orders = new LinkedHashMap<>();
    private final AtomicInteger seq = new AtomicInteger(1);
    Order placeOrder(String product, int qty, double price) {
        if (qty <= 0)   throw new IllegalArgumentException("Qty must be positive");
        if (price <= 0) throw new IllegalArgumentException("Price must be positive");
        String id = "ORD-" + seq.getAndIncrement();
        Order o = new Order(id, product, qty, price, OrderStatus.PENDING);
        orders.put(id, o); return o;
    }
    Order getOrder(String id) {
        if (!orders.containsKey(id)) throw new IllegalArgumentException("Not found: " + id);
        return orders.get(id);
    }
    Order cancelOrder(String id) {
        Order o = getOrder(id);
        if (o.status() == OrderStatus.SHIPPED) throw new IllegalStateException("Cannot cancel shipped order");
        Order cancelled = o.withStatus(OrderStatus.CANCELLED);
        orders.put(id, cancelled); return cancelled;
    }
    int count() { return orders.size(); }
}
import org.junit.jupiter.api.*;
import static org.junit.jupiter.api.Assertions.*;
class OrderServiceTest {
    OrderService service;
    @BeforeEach void setUp() { service = new OrderService(); }
    @Test void placeOrder_returnsOrderWithIdAndPending() {
        Order o = service.placeOrder("Mouse", 2, 799);
        assertNotNull(o.id()); assertEquals(OrderStatus.PENDING, o.status()); }
    @Test void placeOrder_zeroQty_throwsIllegalArgument() {
        assertThrows(IllegalArgumentException.class, () -> service.placeOrder("Mouse", 0, 799)); }
    @Test void placeOrder_negativePrice_throws() {
        assertThrows(IllegalArgumentException.class, () -> service.placeOrder("Mouse", 1, -1)); }
    @Test void getOrder_validId_returnsOrder() {
        Order placed = service.placeOrder("Mouse", 1, 799);
        assertEquals(placed.id(), service.getOrder(placed.id()).id()); }
    @Test void getOrder_unknownId_throwsIllegalArgument() {
        assertThrows(IllegalArgumentException.class, () -> service.getOrder("ORD-999")); }
    @Test void cancelOrder_pendingOrder_becomesCancelled() {
        Order o = service.placeOrder("Mouse", 1, 799);
        assertEquals(OrderStatus.CANCELLED, service.cancelOrder(o.id()).status()); }
    @Test void cancelOrder_shippedOrder_throwsIllegalState() {
        Order o = service.placeOrder("Mouse", 1, 799);
        service.orders.put(o.id(), o.withStatus(OrderStatus.SHIPPED));
        assertThrows(IllegalStateException.class, () -> service.cancelOrder(o.id())); }
    @Test void count_updatesAfterEachOrder() {
        assertEquals(0, service.count());
        service.placeOrder("Mouse", 1, 799);
        service.placeOrder("Keyboard", 2, 1999);
        assertEquals(2, service.count()); }
}
